def gcd2(a: Int, b: Int) -> Int:
    var x = a
    var y = b
    while y != 0:
        var t = y
        y = x % y
        x = t
    return x

def lcm(a: Int, b: Int) -> Int:
    if a == 0 or b == 0:
        return 0
    return a // gcd2(a, b) * b

def is_prime(n: Int) -> Bool:
    if n < 2:
        return False
    var i = 2
    while i * i <= n:
        if n % i == 0:
            return False
        i += 1
    return True

def sieve_count(n: Int) -> Int:
    if n < 2:
        return 0
    var sieve = List[Bool]()
    for _i in range(n + 1):
        sieve.append(True)
    sieve[0] = False
    sieve[1] = False
    var i = 2
    while i * i <= n:
        if sieve[i]:
            var j = i * i
            while j <= n:
                sieve[j] = False
                j += i
        i += 1
    var c = 0
    for k in range(2, n + 1):
        if sieve[k]:
            c += 1
    return c

def collatz_len(n: Int) -> Int:
    var x = n
    var c = 0
    while x != 1:
        if x % 2 == 0:
            x = x // 2
        else:
            x = 3 * x + 1
        c += 1
    return c

def sum_digits(n: Int) -> Int:
    var x = n
    if x < 0:
        x = -x
    var s = 0
    while x > 0:
        s += x % 10
        x = x // 10
    return s

def reverse_int(n: Int) -> Int:
    var sign = -1 if n < 0 else 1
    var x = n
    if x < 0:
        x = -x
    var r = 0
    while x > 0:
        r = r * 10 + x % 10
        x = x // 10
    return sign * r

def climb_stairs(n: Int) -> Int:
    if n <= 2:
        return n
    var a = 1
    var b = 2
    for _i in range(3, n + 1):
        var t = a + b
        a = b
        b = t
    return b

def coin_count(amount: Int) -> Int:
    var coins: List[Int] = [1, 5, 10, 25]
    var dp = List[Int]()
    for _i in range(amount + 1):
        dp.append(1000000)
    dp[0] = 0
    for c in range(len(coins)):
        for a in range(coins[c], amount + 1):
            if dp[a - coins[c]] + 1 < dp[a]:
                dp[a] = dp[a - coins[c]] + 1
    return dp[amount]

def ackermann(m: Int, n: Int) -> Int:
    if m == 0:
        return n + 1
    if n == 0:
        return ackermann(m - 1, 1)
    return ackermann(m - 1, ackermann(m, n - 1))

def fib_rec(n: Int) -> Int:
    if n < 2:
        return n
    return fib_rec(n - 1) + fib_rec(n - 2)

def sum_to_n(n: Int) -> Int:
    if n <= 0:
        return 0
    return n + sum_to_n(n - 1)

def newton_sqrt(x: Float64) -> Float64:
    if x <= 0.0:
        return 0.0
    var g = x
    for _i in range(50):
        g = 0.5 * (g + x / g)
    return g

def gcd3(a: Int, b: Int) -> Int:
    var x = a
    var y = b
    while y != 0:
        var t = y
        y = x % y
        x = t
    return x

def reduce_num(num: Int, den: Int) -> Int:
    var an = -num if num < 0 else num
    var ad = -den if den < 0 else den
    var g = gcd3(an, ad)
    if g == 0:
        return num
    return num // g

def factorial_iter(n: Int) -> Int:
    var r = 1
    for i in range(2, n + 1):
        r *= i
    return r
